250	% CDL-D/E: LOS dominant → even worse for rank
251	channel = nrCDLChannel;
252	channel.DelayProfile         = 'CDL-B';     % Changed: CDL-C→CDL-B for rank-4 test
253	channel.DelaySpread          = 100e-9;       % 100ns
254	channel.MaximumDopplerShift  = 5;            % 5 Hz (low mobility)
255	channel.CarrierFrequency     = 3.5e9;        % 3.5 GHz (n78)
256	
257	% Antenna array configuration
258	channel.TransmitAntennaArray.Size           = gnbArraySize;
259	channel.TransmitAntennaArray.ElementSpacing = [0.5 0.5 1 1];  % in wavelengths
260	channel.ReceiveAntennaArray.Size            = ueArraySize;
261	channel.ReceiveAntennaArray.ElementSpacing  = [0.5 0.5 1 1];
262	
263	% Set sample rate from OFDM info
264	ofdmInfo = nrOFDMInfo(carrier);
265	channel.SampleRate = ofdmInfo.SampleRate;
266	
267	fprintf('\n--- Channel Configuration ---\n');
268	fprintf('Channel model: %s\n', channel.DelayProfile);
269	fprintf('Delay spread: %.0f ns\n', channel.DelaySpread*1e9);
270	fprintf('Doppler: %.1f Hz\n', channel.MaximumDopplerShift);
271	fprintf('Carrier freq: %.1f GHz\n', channel.CarrierFrequency/1e9);
272	fprintf('gNB array: %s -> %d antennas\n', mat2str(gnbArraySize), prod(gnbArraySize));
273	fprintf('UE array:  %s -> %d antennas\n', mat2str(ueArraySize), prod(ueArraySize));
274	
275	%% ========================================================================
276	%  SECTION 6: TRANSMIT THROUGH CHANNEL + AWGN
277	%  ========================================================================
278	
279	% OFDM modulation of full 2-slot grid (single call)
280	carrier.NSlot = 0;
281	[txWaveform, ofdmModInfo] = nrOFDMModulate(carrier, txGrid_2slots);
282	
283	% Zero-pad for channel delay
284	chInfo = info(channel);
285	maxChDelay = chInfo.MaximumChannelDelay;
286	txWaveform = [txWaveform; zeros(maxChDelay, size(txWaveform, 2))];
287	
288	% Pass through CDL-C channel ONCE with the full 2-slot waveform.
289	% The channel is stateful: internal time advances continuously, giving
290	% physically correct temporal correlation between slots. Do NOT split into
291	% 2 calls or reset between slots.
292	[rxWaveform, pathGains, sampleTimes] = channel(txWaveform);
293	
294	% SNR configuration
295	SNRdB = 20;  % Realistic SNR for channel estimation evaluation
296	SNR = 10^(SNRdB/10);
297	N0 = 1/sqrt(2.0 * nRxAntennas * double(ofdmInfo.Nfft) * SNR);
298	
299	rng(42);  % Reproducible
300	noise = N0 * complex(randn(size(rxWaveform)), randn(size(rxWaveform)));
301	rxWaveform = rxWaveform + noise;
302	
303	fprintf('\n--- Transmission ---\n');
304	fprintf('SNR: %d dB\n', SNRdB);
305	fprintf('Noise variance N0: %.2e\n', N0^2);
306	fprintf('txWaveform size: [%s]\n', num2str(size(txWaveform)));
307	
308	%% ========================================================================
309	%  SECTION 7: TIMING SYNC + OFDM DEMOD
310	%  ========================================================================
311	
312	% Timing estimation using Resource #0 (Slot 0) as reference
313	carrier.NSlot = 0;
314	refSym = allCsirsSym{1};
315	refInd = allCsirsInd{1};
316	offset = nrTimingEstimate(carrier, rxWaveform, refInd, refSym);
317	fprintf('\nTiming offset: %d samples\n', offset);
318	
319	rxWaveform = rxWaveform(1+offset:end, :);
320	
321	% OFDM demodulation of full 2-slot waveform (single call)
322	carrier.NSlot = 0;
323	rxGrid_2slots = nrOFDMDemodulate(carrier, rxWaveform);
324	fprintf('rxGrid_2slots size: [%s]\n', num2str(size(rxGrid_2slots)));
325	
326	% Split into per-slot grids for per-resource channel estimation
327	nSymPerSlot  = carrier.SymbolsPerSlot;  % 14
328	rxGrid_slot0 = rxGrid_2slots(:, 1:nSymPerSlot, :);
329	rxGrid_slot1 = rxGrid_2slots(:, (nSymPerSlot+1):(2*nSymPerSlot), :);
330	
331	%% ========================================================================
332	%  SECTION 8: CHANNEL ESTIMATION (PER RESOURCE, THEN COMBINE)
333	%  ========================================================================
334	%
335	%  Each resource yields H_est of size [K x 14 x nRx x 32].
336	%  R0, R1 estimated from rxGrid_slot0; R2, R3 from rxGrid_slot1.
337	%  Combined H_est_full: [K x 28 x nRx x 128].
338	%  CDM lengths for Row 18: [2 4] (FD-CDM2 x TD-CDM4).
339	
340	nSubcarriers = carrier.NSizeGrid * 12;
341	H_est_full   = zeros(nSubcarriers, nSymbols_2slots, nRxAntennas, nTxAntennas);
342	nVar_all     = zeros(1, nResources);
343	
344	for resIdx = 1:nResources
345	    slotNum = slotAssign(resIdx);
346	    carrier.NSlot = slotNum;
347	
348	    if slotNum == 0
349	        rxGrid_slot = rxGrid_slot0;
350	    else
351	        rxGrid_slot = rxGrid_slot1;
352	    end
353	
354	    [H_est_res, nVar_res] = nrChannelEstimate(carrier, rxGrid_slot, ...
355	        allCsirsInd{resIdx}, allCsirsSym{resIdx}, ...
356	        'CDMLengths', cdmLengths);
357	
358	    % H_est_res: [K x 14 x nRx x 32]
359	    portStart = (resIdx - 1) * nPortsPerRes + 1;
360	    portEnd   = resIdx * nPortsPerRes;
361	    symStart  = slotNum * nSymPerSlot + 1;
362	    symEnd    = (slotNum + 1) * nSymPerSlot;
363	
364	    H_est_full(:, symStart:symEnd, :, portStart:portEnd) = H_est_res;
365	    nVar_all(resIdx) = nVar_res;
366	
367	    fprintf('Resource #%d (Slot %d): H_est size [%s], nVar = %.4e\n', ...
368	        resIdx-1, slotNum, num2str(size(H_est_res)), nVar_res);
369	end
370	
371	nVar_avg = mean(nVar_all);
372	fprintf('\nH_est_full size: [%s]\n', num2str(size(H_est_full)));
373	fprintf('Average noise variance: %.4e\n', nVar_avg);
374	
375	%% ========================================================================
376	%  SECTION 9: CHANNEL ESTIMATION ERROR ANALYSIS
377	%  ========================================================================
378	
379	% Perfect channel estimates for both slots (ground truth)
380	pathFilters = getPathFilters(channel);
381	
382	carrier.NSlot = 0;
383	H_actual_slot0 = nrPerfectChannelEstimate(carrier, pathGains, pathFilters, offset, sampleTimes);
384	carrier.NSlot = 1;
385	H_actual_slot1 = nrPerfectChannelEstimate(carrier, pathGains, pathFilters, offset, sampleTimes);
386	
387	% Combine into 2-slot ground truth [K x 28 x nRx x nTx]
388	H_actual = cat(2, H_actual_slot0, H_actual_slot1);
389	
390	% Compare H_est_full vs H_actual.
391	% H_est_full is populated per resource in its own slot only:
392	%   Ports 1-64  (Res 0,1 — Slot 0): sym 1-14  non-zero, sym 15-28 = 0
393	%   Ports 65-128 (Res 2,3 — Slot 1): sym 15-28 non-zero, sym 1-14  = 0
394	% Comparing against H_actual (dense, all 28 sym) would count the zeros as
395	% error.  Correct approach: evaluate NMSE per resource at its own slot.
396	H_actual_trimmed = H_actual(:, :, :, 1:size(H_est_full, 4));
397	
398	mse_per_port  = zeros(nTxAntennas, 1);
399	ref_per_port  = zeros(nTxAntennas, 1);
400	for resIdx = 1:nResources
401	    portStart = (resIdx-1)*nPortsPerRes + 1;
402	    portEnd   = resIdx*nPortsPerRes;
403	    slotNum   = slotAssign(resIdx);
404	    symStart  = slotNum*nSymPerSlot + 1;
405	    symEnd    = (slotNum+1)*nSymPerSlot;
406	
407	    H_e = H_est_full(:, symStart:symEnd, :, portStart:portEnd);     % [K×14×nRx×32]
408	    H_a = H_actual_trimmed(:, symStart:symEnd, :, portStart:portEnd);
409	    err = H_e - H_a;
410	    for p = 1:nPortsPerRes
411	        mse_per_port(portStart+p-1) = mean(abs(err(:,:,:,p)).^2, 'all');
412	        ref_per_port(portStart+p-1) = mean(abs(H_a(:,:,:,p)).^2, 'all');
413	    end
414	end
415	nmse_per_port = mse_per_port ./ ref_per_port;
416	
417	fprintf('\n--- Channel Estimation Error (per-resource, per-slot) ---\n');
418	fprintf('Overall MSE:  %.4e\n', mean(mse_per_port));
419	fprintf('Overall NMSE: %.2f dB\n', 10*log10(mean(nmse_per_port)));
420	
421	figure('Name', 'Channel Estimation Quality', 'Position', [100 100 1400 400]);
422	
423	subplot(1,3,1);
424	plot(0:nTxAntennas-1, 10*log10(nmse_per_port), '-o', 'MarkerSize', 3);
425	xlabel('CSI-RS Port Index'); ylabel('NMSE (dB)');
426	title('NMSE per Port (128 ports, 2 slots)');
427	grid on;
428	xline([32 64 96]-0.5, '--r', {'Res#1','Res#2','Res#3'});
429	
430	subplot(1,3,2);
431	imagesc(abs(H_est_full(:, :, 1, 1)));
432	axis xy; colorbar;
433	xlabel('OFDM Symbol (0-27)'); ylabel('Subcarrier');
434	title('|H_{est}| (Rx0, Port0, 2 slots)');
435	
436	subplot(1,3,3);
437	imagesc(abs(H_actual_trimmed(:, :, 1, 1)));
438	axis xy; colorbar;
439	xlabel('OFDM Symbol (0-27)'); ylabel('Subcarrier');
440	title('|H_{actual}| (Rx0, Port0, 2 slots)');
