%  COMPARISON TABLE (ALL mode)
% =========================================================================
if strcmp(selectedApproach, 'ALL')
    % Reuse SVD results already computed in Approach B (no recomputation)
    sv_all     = singularValues_B;
    snr_sv_all = snr_sv_B;
    fprintf('\n  --- Channel Rank Analysis (SVD of H_wb) ---\n');
