            bp_B(ai) = abs(a_full'*w1_B)^2;
        end
        plot(azAngles, 10*log10(bp_B/max(bp_B)), 'LineWidth', 1.5);
        xlabel('Azimuth (degrees)'); ylabel('Normalized Gain (dB)');
